import{_ as n,c as t,o as i,a1 as r}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse('{"title":"Monitoring & Fehlerbehebung: Anfragenprotokoll-Analyse","description":"Erfahren Sie mehr über Proxy Monitor von Antigravity Tools. Durch Anfragenprotokolle, Filterung und Detail-Wiederherstellung lokalisieren Sie 401/429/5xx-Fehler und Streaming-Unterbrechungen.","frontmatter":{"title":"Monitoring & Fehlerbehebung: Anfragenprotokoll-Analyse","sidebarTitle":"Anfragenprotokoll-Fehlerbehebung","subtitle":"Monitoring & Fehlerbehebung: Anfragenprotokoll-Analyse","description":"Erfahren Sie mehr über Proxy Monitor von Antigravity Tools. Durch Anfragenprotokolle, Filterung und Detail-Wiederherstellung lokalisieren Sie 401/429/5xx-Fehler und Streaming-Unterbrechungen.","tags":["Erweitert","Monitoring","Fehlerbehebung","Proxy","Protokolle"],"prerequisite":["/de/lbjlaq/Antigravity-Manager/start/proxy-and-first-client/","/de/lbjlaq/Antigravity-Manager/start/first-run-data/","/de/lbjlaq/Antigravity-Manager/advanced/config/"],"order":6},"headers":[],"relativePath":"de/lbjlaq/Antigravity-Manager/advanced/monitoring/index.md","filePath":"de/lbjlaq/Antigravity-Manager/advanced/monitoring/index.md"}'),o={name:"de/lbjlaq/Antigravity-Manager/advanced/monitoring/index.md"};function a(s,e,l,d,u,h){return i(),t("div",null,[...e[0]||(e[0]=[r(`<h1 id="proxy-monitor-anfragenprotokolle-filterung-detail-wiederherstellung-und-export" tabindex="-1">Proxy Monitor: Anfragenprotokolle, Filterung, Detail-Wiederherstellung und Export <a class="header-anchor" href="#proxy-monitor-anfragenprotokolle-filterung-detail-wiederherstellung-und-export" aria-label="Permalink to &quot;Proxy Monitor: Anfragenprotokolle, Filterung, Detail-Wiederherstellung und Export&quot;">​</a></h1><p>Sie haben den lokalen Reverse-Proxy bereits am Laufen, aber sobald 401/429/500-Fehler, Streaming-Unterbrechungen oder plötzliche Konto-/Modellwechsel auftreten, wird die Fehlerbehebung schnell zu einem Rätselraten.</p><p>In dieser Lektion geht es nur um ein Thema: Mit <strong>Proxy Monitor</strong> jeden Aufruf in &quot;rekonstruierbare Beweise&quot; zu verwandeln, damit Sie wissen, woher die Anfrage kam, welchen Endpunkt sie getroffen hat, welches Konto verwendet wurde, ob das Modell zugeordnet wurde und wie groß der Token-Verbrauch ungefähr war.</p><h2 id="was-sie-nach-dieser-lektion-konnen-konnen" tabindex="-1">Was Sie nach dieser Lektion können können <a class="header-anchor" href="#was-sie-nach-dieser-lektion-konnen-konnen" aria-label="Permalink to &quot;Was Sie nach dieser Lektion können können&quot;">​</a></h2><ul><li>Öffnen/Pausieren der Aufzeichnung auf der Seite <code>/monitor</code> und Verstehen, ob dies die Token-Statistiken beeinflusst</li><li>Schnelles Lokalisieren eines Anfragendatensatzes mit Suchfeld, Schnellfilter und Kontofilter</li><li>Anzeigen und Kopieren von Request/Response-Nachrichten im Detail-Popup zum Nachvollziehen von Fehlern</li><li>Kenntnis der Datenspeicherposition von Proxy Monitor (<code>proxy_logs.db</code>) und des Löschverhaltens</li><li>Verständnis der tatsächlichen Fähigkeitsgrenzen von &quot;Protokolle exportieren&quot; in der aktuellen Version (GUI vs Backend-Befehle)</li></ul><h2 id="ihr-aktuelles-problem" tabindex="-1">Ihr aktuelles Problem <a class="header-anchor" href="#ihr-aktuelles-problem" aria-label="Permalink to &quot;Ihr aktuelles Problem&quot;">​</a></h2><ul><li>Sie sehen nur &quot;Aufruf fehlgeschlagen/Timeout&quot;, wissen aber nicht, ob der Fehler upstream, im Proxy oder in der Client-Konfiguration aufgetreten ist</li><li>Sie vermuten, dass eine Modellzuordnung oder ein Kontorundlauf ausgelöst wurde, haben aber keine Beweiskette</li><li>Sie möchten die vollständige Payload einer Anfrage nachvollziehen (insbesondere Streaming/Thinking), sehen diese aber nicht in den Protokollen</li></ul><h2 id="wann-sie-diese-methode-verwenden-sollten" tabindex="-1">Wann Sie diese Methode verwenden sollten <a class="header-anchor" href="#wann-sie-diese-methode-verwenden-sollten" aria-label="Permalink to &quot;Wann Sie diese Methode verwenden sollten&quot;">​</a></h2><ul><li>Sie müssen untersuchen: 401-Authentifizierungsfehler, 429-Ratenbegrenzung, 5xx-Upstream-Fehler, Streaming-Unterbrechungen</li><li>Sie möchten bestätigen, welches Konto eine bestimmte Anfrage verwendet hat (<code>X-Account-Email</code>)</li><li>Sie arbeiten an einer Modellrouting-Strategie und möchten verifizieren &quot;Client-Modellname → tatsächlich zugeordneter Modellname&quot;</li></ul><h2 id="🎒-vorbereitungen-vor-dem-start" tabindex="-1">🎒 Vorbereitungen vor dem Start <a class="header-anchor" href="#🎒-vorbereitungen-vor-dem-start" aria-label="Permalink to &quot;🎒 Vorbereitungen vor dem Start&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Voraussetzungen</p><p>Proxy Monitor zeichnet die Anfragen auf, die vom Reverse-Proxy empfangen wurden. Sie müssen mindestens Folgendes funktionierend haben:</p><ul><li>Der Reverse-Proxy ist gestartet und erreichbar unter <code>/healthz</code></li><li>Sie kennen die Base-URL und den Port des aktuellen Reverse-Proxys</li></ul><p>Wenn dies noch nicht funktioniert, lesen Sie zuerst <strong><a href="/docs/opencodedocs/de/lbjlaq/Antigravity-Manager/start/proxy-and-first-client/">Lokalen Reverse-Proxy starten und ersten Client integrieren</a></strong>.</p></div><h2 id="was-ist-proxy-monitor" tabindex="-1">Was ist Proxy Monitor? <a class="header-anchor" href="#was-ist-proxy-monitor" aria-label="Permalink to &quot;Was ist Proxy Monitor?&quot;">​</a></h2><p><strong>Proxy Monitor</strong> ist das in Antigravity Tools integrierte &quot;Anfragenprotokoll-Dashboard&quot;. Nachdem jede Anfrage den lokalen Reverse-Proxy erreicht hat, zeichnet es Zeit, Pfad, Statuscode, Dauer, Modell und Protokoll auf und versucht, die Token-Nutzung aus der Antwort zu extrahieren. Sie können auch auf einen einzelnen Datensatz klicken, um Anfrage- und Antwortnachrichten anzuzeigen und用它来 Fehlerursachen und Routing/Konto-Auswahl-Ergebnisse nachvollzuziehen.</p><div class="info custom-block"><p class="custom-block-title">Datenspeicherposition</p><p>Die Protokolle von Proxy Monitor werden in einer SQLite-Datenbank im Datenverzeichnis gespeichert: <code>proxy_logs.db</code>. Wie Sie das Datenverzeichnis finden und sichern, wird empfohlen, zuerst <strong><a href="/docs/opencodedocs/de/lbjlaq/Antigravity-Manager/start/first-run-data/">Erstes Starten müssen Sie verstehen: Datenverzeichnis, Protokolle, Tray und Autostart</a></strong> zu lesen.</p></div><h2 id="kernkonzept-die-6-felder-die-sie-im-auge-behalten-mussen" tabindex="-1">Kernkonzept: Die 6 Felder, die Sie im Auge behalten müssen <a class="header-anchor" href="#kernkonzept-die-6-felder-die-sie-im-auge-behalten-mussen" aria-label="Permalink to &quot;Kernkonzept: Die 6 Felder, die Sie im Auge behalten müssen&quot;">​</a></h2><p>In einem Datensatz von Proxy Monitor (Backend-Struktur <code>ProxyRequestLog</code>) sind die folgenden Felder am nützlichsten:</p><table tabindex="0"><thead><tr><th>Feld</th><th>Damit beantworten Sie welche Frage</th></tr></thead><tbody><tr><td><code>status</code></td><td>War diese Anfrage erfolgreich oder fehlgeschlagen (200-399 vs andere)</td></tr><tr><td><code>url</code> / <code>method</code></td><td>Welchen Endpunkt haben Sie tatsächlich getroffen (z.B. <code>/v1/messages</code>, <code>/v1/chat/completions</code>)</td></tr><tr><td><code>protocol</code></td><td>Welches Protokoll ist dies (OpenAI / Claude(Anthropic) / Gemini)</td></tr><tr><td><code>account_email</code></td><td>Welches Konto wurde für diese Anfrage最终 verwendet (aus dem Antwortheader <code>X-Account-Email</code>)</td></tr><tr><td><code>model</code> / <code>mapped_model</code></td><td>Wurde der vom Client angeforderte Modellname durch &quot;Routing/Zuordnung&quot; in ein anderes Modell geändert</td></tr><tr><td><code>input_tokens</code> / <code>output_tokens</code></td><td>Token-Verbrauch dieser Anfrage (nur wenn extrahierbar)</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">Verwenden Sie zuerst &quot;Zusammenfassung&quot;, klicken Sie bei Bedarf auf &quot;Details&quot;</p><p>Die Listenseite zeigt nur Zusammenfassungen (ohne request/response body). Wenn Sie auf einen Datensatz klicken, werden die vollständigen Details vom Backend geladen, um zu vermeiden, dass zu viele große Felder auf einmal abgerufen werden.</p></div><h2 id="folgen-sie-mir-fuhren-sie-mit-einem-aufruf-den-monitoring-kreislauf-durch" tabindex="-1">Folgen Sie mir: Führen Sie mit einem Aufruf den &quot;Monitoring-Kreislauf&quot; durch <a class="header-anchor" href="#folgen-sie-mir-fuhren-sie-mit-einem-aufruf-den-monitoring-kreislauf-durch" aria-label="Permalink to &quot;Folgen Sie mir: Führen Sie mit einem Aufruf den &quot;Monitoring-Kreislauf&quot; durch&quot;">​</a></h2><h3 id="schritt-1-erstellen-sie-zuerst-eine-sichere-anfrage" tabindex="-1">Schritt 1: Erstellen Sie zuerst eine &quot;sichere&quot; Anfrage <a class="header-anchor" href="#schritt-1-erstellen-sie-zuerst-eine-sichere-anfrage" aria-label="Permalink to &quot;Schritt 1: Erstellen Sie zuerst eine &quot;sichere&quot; Anfrage&quot;">​</a></h3><p><strong>Warum</strong> Proxy Monitor zeichnet nur Anfragen auf, die vom Reverse-Proxy empfangen wurden. Überprüfen Sie zuerst mit einer einfachsten Anfrage, ob &quot;Aufzeichnung stattfindet&quot;, bevor Sie über Filterung und Details sprechen.</p><div class="vp-code-group vp-adaptive-theme"><div class="tabs"><input type="radio" name="group-76Q-R" id="tab-DSrPauo" checked><label data-title="macOS/Linux" for="tab-DSrPauo">macOS/Linux</label><input type="radio" name="group-76Q-R" id="tab-fhj3GlC"><label data-title="Windows" for="tab-fhj3GlC">Windows</label></div><div class="blocks"><div class="language-bash vp-adaptive-theme active"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">## 1) Health-Check (definitiv vorhandener Endpunkt)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;http://127.0.0.1:PORT/healthz&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">## 2) Fordern Sie einmal models an (wenn Sie Authentifizierung aktiviert haben, denken Sie daran, Header hinzuzufügen)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;http://127.0.0.1:PORT/v1/models&quot;</span></span></code></pre></div><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">## 1) Health-Check (definitiv vorhandener Endpunkt)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">curl </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;http://127.0.0.1:PORT/healthz&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">## 2) Fordern Sie einmal models an (wenn Sie Authentifizierung aktiviert haben, denken Sie daran, Header hinzuzufügen)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">curl </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;http://127.0.0.1:PORT/v1/models&quot;</span></span></code></pre></div></div></div><p><strong>Sie sollten sehen</strong>: Das Terminal gibt <code>{&quot;status&quot;:&quot;ok&quot;}</code> (oder ähnliches JSON) zurück sowie die Antwort von <code>/v1/models</code> (erfolgreich oder 401 ist in Ordnung).</p><h3 id="schritt-2-offnen-sie-die-monitor-seite-und-bestatigen-sie-den-aufzeichnungsstatus" tabindex="-1">Schritt 2: Öffnen Sie die Monitor-Seite und bestätigen Sie den &quot;Aufzeichnungsstatus&quot; <a class="header-anchor" href="#schritt-2-offnen-sie-die-monitor-seite-und-bestatigen-sie-den-aufzeichnungsstatus" aria-label="Permalink to &quot;Schritt 2: Öffnen Sie die Monitor-Seite und bestätigen Sie den &quot;Aufzeichnungsstatus&quot;&quot;">​</a></h3><p><strong>Warum</strong> Proxy Monitor hat einen &quot;Aufzeichnen/Pausieren&quot;-Schalter. Sie müssen zuerst den aktuellen Status bestätigen, sonst könnten Sie weiterhin Anfragen stellen, aber die Liste bleibt immer leer.</p><p>Öffnen Sie in Antigravity Tools das <strong>API-Monitoring-Dashboard</strong> in der Seitenleiste (Route <code>/monitor</code>).</p><p>Ganz oben auf der Seite gibt es einen Button mit einem Punkt:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌───────────────────────────────────────────┐</span></span>
<span class="line"><span>│  ● Aufzeichnung läuft   [Suchfeld]  [Aktualisieren] [Löschen]      │</span></span>
<span class="line"><span>└───────────────────────────────────────────┘</span></span></code></pre></div><p>Wenn Sie &quot;Pausiert&quot; sehen, klicken Sie einmal, um auf &quot;Aufzeichnung läuft&quot; zu wechseln.</p><p><strong>Sie sollten sehen</strong>: Der Button-Status ändert sich zu &quot;Aufzeichnung läuft&quot;; in der Liste beginnen die Anfragendatensätze der vorherigen Anfragen zu erscheinen.</p><h3 id="schritt-3-lokalisieren-sie-einen-datensatz-mit-suche-schnellfilter" tabindex="-1">Schritt 3: Lokalisieren Sie einen Datensatz mit &quot;Suche + Schnellfilter&quot; <a class="header-anchor" href="#schritt-3-lokalisieren-sie-einen-datensatz-mit-suche-schnellfilter" aria-label="Permalink to &quot;Schritt 3: Lokalisieren Sie einen Datensatz mit &quot;Suche + Schnellfilter&quot;&quot;">​</a></h3><p><strong>Warum</strong> Bei der tatsächlichen Fehlerbehebung erinnern Sie sich normalerweise nur an ein Fragment: Der Pfad enthält <code>messages</code>, oder der Statuscode ist <code>401</code>, oder der Modellname enthält <code>gemini</code>. Das Suchfeld ist genau für solche Erinnerungen konzipiert.</p><p>Die Suche von Proxy Monitor behandelt Ihre Eingabe als ein &quot;unscharfes Schlüsselwort&quot; und stimmt diese Felder im Backend mit SQL <code>LIKE</code> ab:</p><ul><li><code>url</code></li><li><code>method</code></li><li><code>model</code></li><li><code>status</code></li><li><code>account_email</code></li></ul><p>Sie können einige typische Schlüsselwörter ausprobieren:</p><ul><li><code>healthz</code></li><li><code>models</code></li><li><code>401</code> (wenn Sie gerade einen 401 erzeugt haben)</li></ul><p>Sie können auch auf die &quot;Schnellfilter&quot;-Buttons klicken: <strong>Nur Fehler / Chat / Gemini / Claude / Bilder</strong>.</p><p><strong>Sie sollten sehen</strong>: Die Liste enthält nur die Art von Anfragen, die Sie erwarten.</p><h3 id="schritt-4-offnen-sie-details-stellen-sie-anfrage-nachricht-antwort-nachricht-wieder-her" tabindex="-1">Schritt 4: Öffnen Sie Details, stellen Sie &quot;Anfrage-Nachricht + Antwort-Nachricht&quot; wieder her <a class="header-anchor" href="#schritt-4-offnen-sie-details-stellen-sie-anfrage-nachricht-antwort-nachricht-wieder-her" aria-label="Permalink to &quot;Schritt 4: Öffnen Sie Details, stellen Sie &quot;Anfrage-Nachricht + Antwort-Nachricht&quot; wieder her&quot;">​</a></h3><p><strong>Warum</strong> Die Liste reicht nur, um zu beantworten &quot;was ist passiert&quot;. Um zu beantworten &quot;warum&quot;, müssen Sie normalerweise die vollständige Anfrage/Antwort-Payload ansehen.</p><p>Klicken Sie auf einen beliebigen Datensatz, und das Detail-Fenster wird angezeigt. Sie können sich auf Folgendes konzentrieren:</p><ul><li><code>Protokoll</code> (OpenAI/Claude/Gemini)</li><li><code>Verwendetes Modell</code> und <code>Zugeordnetes Modell</code></li><li><code>Verwendetes Konto</code></li><li><code>Token-Verbrauch (Eingabe/Ausgabe)</code></li></ul><p>Kopieren Sie dann mit den Buttons:</p><ul><li><code>Anfrage-Nachricht (Request)</code></li><li><code>Antwort-Nachricht (Response)</code></li></ul><p><strong>Sie sollten sehen</strong>: Im Detail gibt es zwei JSON- (oder Text-) Vorschauen; nach dem Kopieren können Sie sie in Tickets/Notizen einfügen, um sie nachzuvollziehen.</p><h3 id="schritt-5-wenn-sie-von-grund-auf-neu-reproduzieren-mussen-loschen-sie-protokolle" tabindex="-1">Schritt 5: Wenn Sie &quot;von Grund auf neu reproduzieren&quot; müssen, löschen Sie Protokolle <a class="header-anchor" href="#schritt-5-wenn-sie-von-grund-auf-neu-reproduzieren-mussen-loschen-sie-protokolle" aria-label="Permalink to &quot;Schritt 5: Wenn Sie &quot;von Grund auf neu reproduzieren&quot; müssen, löschen Sie Protokolle&quot;">​</a></h3><p><strong>Warum</strong> Bei der Fehlerbehebung haben Sie am meisten Angst vor &quot;alten Daten, die die Beurteilung stören&quot;. Nach dem Löschen und erneuten Reproduzieren sind Erfolg/Fehler sehr klar.</p><p>Klicken Sie auf den &quot;Löschen&quot;-Button oben, und ein Bestätigungsdialog wird angezeigt.</p><div class="danger custom-block"><p class="custom-block-title">Dies ist eine irreversible Operation</p><p>Das Löschen entfernt alle Datensätze aus <code>proxy_logs.db</code>.</p></div><p><strong>Sie sollten sehen</strong>: Nach Bestätigung wird die Liste geleert, die statistischen Zahlen kehren zu 0 zurück.</p><h2 id="kontrollpunkt-✅" tabindex="-1">Kontrollpunkt ✅ <a class="header-anchor" href="#kontrollpunkt-✅" aria-label="Permalink to &quot;Kontrollpunkt ✅&quot;">​</a></h2><ul><li>[ ] Sie können Ihre soeben gesendeten <code>/healthz</code>- oder <code>/v1/models</code>-Datensätze auf <code>/monitor</code> sehen</li><li>[ ] Sie können einen bestimmten Datensatz mit dem Suchfeld filtern (z.B. durch Eingabe von <code>healthz</code>)</li><li>[ ] Sie können auf einen Datensatz klicken, um Anfrage/Antwort-Nachrichten zu sehen und sie zu kopieren</li><li>[ ] Sie wissen, dass das Löschen von Protokollen alle historischen Datensätze direkt entfernt</li></ul><h2 id="warnung-vor-fallstricken" tabindex="-1">Warnung vor Fallstricken <a class="header-anchor" href="#warnung-vor-fallstricken" aria-label="Permalink to &quot;Warnung vor Fallstricken&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Szenario</th><th>Mögliches Verständnis (❌)</th><th>Tatsächliches Verhalten (✓)</th></tr></thead><tbody><tr><td>&quot;Pausiert&quot; = überhaupt kein Monitoring-Overhead</td><td>Glauben, dass pausierte Anfragen nicht geparst werden</td><td>Pausieren beeinflusst nur, ob in Proxy Monitor-Protokolle geschrieben wird. Aber Anfrage/Antwort-Parsen (einschließlich SSE-Parsen von Streaming-Daten) findet weiterhin statt, nur die geparsten Daten werden nicht gespeichert. Token-Statistiken werden weiterhin aufgezeichnet (unabhängig davon, ob Monitoring aktiviert ist).</td></tr><tr><td>Binäre/große Body-Protokolle sind leer</td><td>Glauben, dass Monitoring kaputt ist</td><td>Binäre Anfrage/Antwort wird als <code>[Binary Request Data]</code> / <code>[Binary Response Data]</code> angezeigt. Antwort-Body über 100 MB wird als <code>[Response too large (&gt;100MB)]</code> gekennzeichnet; Anfrage-Body über das Limit wird nicht aufgezeichnet.</td></tr><tr><td>Wollen Monitor verwenden, um &quot;wer die Anfrage gesendet hat&quot; zu finden</td><td>Glauben, dass Sie den Client-Prozess zurückverfolgen können</td><td>Monitor zeichnet HTTP-Ebenen-Informationen auf (Methode/Pfad/Modell/Konto), enthält aber nicht &quot;aufrufenden Prozessnamen&quot;. Sie müssen die Client-eigenen Protokolle oder System-Netzwerkpaketerfassung kombinieren, um die Quelle zu lokalisieren.</td></tr><tr><td>Wenn Monitoring aktiviert ist, sind Token-Statistiken-Daten anomal</td><td>Glauben, dass dies ein statistischer Fehler ist</td><td>Wenn Monitoring aktiviert ist, können Token-Statistiken zweimal aufgezeichnet werden (einmal am Anfang der Monitoring-Funktion, einmal beim asynchronen Schreiben in die Datenbank). Dies ist das Quellcode-Verhalten der aktuellen Version.</td></tr></tbody></table><h2 id="export-und-langfristige-aufbewahrung-klaren-sie-zuerst-die-fahigkeitsgrenzen" tabindex="-1">Export und langfristige Aufbewahrung: Klären Sie zuerst die Fähigkeitsgrenzen <a class="header-anchor" href="#export-und-langfristige-aufbewahrung-klaren-sie-zuerst-die-fahigkeitsgrenzen" aria-label="Permalink to &quot;Export und langfristige Aufbewahrung: Klären Sie zuerst die Fähigkeitsgrenzen&quot;">​</a></h2><h3 id="_1-was-kann-die-gui-aktuell-tun" tabindex="-1">1) Was kann die GUI aktuell tun? <a class="header-anchor" href="#_1-was-kann-die-gui-aktuell-tun" aria-label="Permalink to &quot;1) Was kann die GUI aktuell tun?&quot;">​</a></h3><p>In der aktuellen Version der Monitor-UI (<code>ProxyMonitor.tsx</code>) können Sie:</p><ul><li>Suchen/Filtern/Blättern</li><li>Details öffnen, um Payload anzuzeigen und zu kopieren</li><li>Alle Protokolle löschen</li></ul><p>Aber es gibt <strong>keinen &quot;Export-Button&quot;</strong> (im Quellcode wurden keine entsprechenden UI gefunden).</p><h3 id="_2-welche-exportfahigkeiten-hat-das-backend-bereits-geeignet-fur-sekundare-entwicklung" tabindex="-1">2) Welche Exportfähigkeiten hat das Backend bereits (geeignet für sekundäre Entwicklung) <a class="header-anchor" href="#_2-welche-exportfahigkeiten-hat-das-backend-bereits-geeignet-fur-sekundare-entwicklung" aria-label="Permalink to &quot;2) Welche Exportfähigkeiten hat das Backend bereits (geeignet für sekundäre Entwicklung)&quot;">​</a></h3><p>Die Tauri-Befehle des Backends bieten zwei Exportmethoden:</p><ul><li><code>export_proxy_logs(file_path)</code>: Exportiert &quot;alle Protokolle&quot; aus der Datenbank als JSON-Datei</li><li><code>export_proxy_logs_json(file_path, json_data)</code>: Schreibt das von Ihnen übergebene JSON-Array formatiert in eine Datei (erfordert, dass die Eingabe ein Array-Format sein muss)</li></ul><p>Wenn Sie die GUI sekundär entwickeln oder Ihr eigenes Aufrufskript schreiben, können Sie diese Befehle direkt wiederverwenden.</p><h3 id="_3-die-einfachste-export-methode-sichern-sie-direkt-proxy-logs-db" tabindex="-1">3) Die einfachste &quot;Export&quot;-Methode: Sichern Sie direkt <code>proxy_logs.db</code> <a class="header-anchor" href="#_3-die-einfachste-export-methode-sichern-sie-direkt-proxy-logs-db" aria-label="Permalink to &quot;3) Die einfachste &quot;Export&quot;-Methode: Sichern Sie direkt \`proxy_logs.db\`&quot;">​</a></h3><p>Da Proxy Monitor im Wesentlichen SQLite ist, können Sie auch <code>proxy_logs.db</code> als &quot;Fehlerbehebungs-Evidenzpaket&quot; zusammen sichern (z.B. zusammen mit <code>token_stats.db</code>). Die Position des Datenverzeichnisses finden Sie unter <strong><a href="/docs/opencodedocs/de/lbjlaq/Antigravity-Manager/start/first-run-data/">Erstes Starten müssen Sie verstehen</a></strong>.</p><h2 id="empfohlene-lekture" tabindex="-1">Empfohlene Lektüre <a class="header-anchor" href="#empfohlene-lekture" aria-label="Permalink to &quot;Empfohlene Lektüre&quot;">​</a></h2><ul><li>Um die Modellzuordnung zu verstehen: <strong><a href="/docs/opencodedocs/de/lbjlaq/Antigravity-Manager/advanced/model-router/">Modell-Routing: Benutzerdefinierte Zuordnung, Platzhalter-Priorität und vordefinierte Strategien</a></strong></li><li>Um Authentifizierungsprobleme zu untersuchen: <strong><a href="/docs/opencodedocs/de/lbjlaq/Antigravity-Manager/faq/auth-401/">401/Authentifizierungsfehler: auth_mode, Header-Kompatibilität und Client-Konfigurations-Checkliste</a></strong></li><li>Um Monitor mit Kostenstatistiken zu kombinieren: Der nächste Abschnitt wird über Token-Stats sprechen (<code>token_stats.db</code>)</li></ul><h2 id="zusammenfassung-dieser-lektion" tabindex="-1">Zusammenfassung dieser Lektion <a class="header-anchor" href="#zusammenfassung-dieser-lektion" aria-label="Permalink to &quot;Zusammenfassung dieser Lektion&quot;">​</a></h2><ul><li>Der Wert von Proxy Monitor ist &quot;rekonstruierbar&quot;: Aufzeichnen von Statuscode/Pfad/Protokoll/Konto/Modellzuordnung/Token-Verbrauch und Bereitstellen von Anfragedetails</li><li>Suche und Schnellfilter sind der Einstieg zur Fehlerbehebung: Verkleinern Sie zuerst den Bereich, klicken Sie dann auf Details, um Payload anzuzeigen</li><li>Löschen von Protokollen ist eine irreversible Operation; Export ist derzeit eher &quot;sekundäre Entwicklungsfähigkeit&quot; und &quot;Sichern der Datenbankdatei&quot;</li></ul><h2 id="vorschau-auf-die-nachste-lektion" tabindex="-1">Vorschau auf die nächste Lektion <a class="header-anchor" href="#vorschau-auf-die-nachste-lektion" aria-label="Permalink to &quot;Vorschau auf die nächste Lektion&quot;">​</a></h2><blockquote><p>In der nächsten Lektion lernen wir <strong><a href="/docs/opencodedocs/de/lbjlaq/Antigravity-Manager/advanced/token-stats/">Token Stats: Kostenperspektive, Statistik-Maßstäbe und Diagramm-Interpretation</a></strong>, um &quot;es fühlt sich teuer an&quot; in quantifizierbare Optimierung zu verwandeln.</p></blockquote><hr><h2 id="anhang-quellcode-referenz" tabindex="-1">Anhang: Quellcode-Referenz <a class="header-anchor" href="#anhang-quellcode-referenz" aria-label="Permalink to &quot;Anhang: Quellcode-Referenz&quot;">​</a></h2><details><summary><strong>Klicken, um Quellcode-Positionen anzuzeigen</strong></summary><blockquote><p>Aktualisierungszeit: 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Funktion</th><th>Dateipfad</th><th>Zeilennummer</th></tr></thead><tbody><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>UI: Konfiguration lesen und enable_logging synchronisieren</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/components/proxy/ProxyMonitor.tsx#L174-L243" target="_blank" rel="noreferrer"><code>src/components/proxy/ProxyMonitor.tsx</code></a></td><td>174-243</td></tr><tr><td>UI: Aufzeichnung umschalten (in config schreiben + set_proxy_monitor_enabled)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/components/proxy/ProxyMonitor.tsx#L254-L267" target="_blank" rel="noreferrer"><code>src/components/proxy/ProxyMonitor.tsx</code></a></td><td>254-267</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>UI: Protokolle löschen (clear_proxy_logs)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/components/proxy/ProxyMonitor.tsx#L389-L403" target="_blank" rel="noreferrer"><code>src/components/proxy/ProxyMonitor.tsx</code></a></td><td>389-403</td></tr><tr><td>UI: Einzeldetails laden (get_proxy_log_detail)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/components/proxy/ProxyMonitor.tsx#L505-L519" target="_blank" rel="noreferrer"><code>src/components/proxy/ProxyMonitor.tsx</code></a></td><td>505-519</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>---</td><td>---</td><td>---</td></tr></tbody></table><p><strong>Wichtige Konstanten</strong>:</p><ul><li><code>MAX_REQUEST_LOG_SIZE = 100 * 1024 * 1024</code>: Maximaler Anfrage-Body, den die Monitoring-Middleware lesen kann (über diesen Wert schlägt das Lesen fehl)</li><li><code>MAX_RESPONSE_LOG_SIZE = 100 * 1024 * 1024</code>: Maximaler Antwort-Body, den die Monitoring-Middleware lesen kann (für große Antworten wie Bilder)</li></ul><p><strong>Wichtige Funktionen/Befehle</strong>:</p><ul><li><code>monitor_middleware(...)</code>: Sammelt Anfrage und Antwort auf HTTP-Ebene und ruft <code>monitor.log_request(...)</code> auf</li><li><code>ProxyMonitor::log_request(...)</code>: Schreibt in Speicher + SQLite und sendet Zusammenfassung über <code>proxy://request</code>-Ereignis</li><li><code>get_proxy_logs_count_filtered(filter, errors_only)</code> / <code>get_proxy_logs_filtered(...)</code>: Filterung und Blättern auf Listenseite</li><li><code>get_proxy_log_detail(log_id)</code>: Lädt den vollständigen request/response-Body eines einzelnen Protokolls</li><li><code>export_proxy_logs(file_path)</code>: Exportiert alle Protokolle in eine JSON-Datei (aktuelle UI hat keinen Button)</li></ul></details>`,74)])])}const p=n(o,[["render",a]]);export{g as __pageData,p as default};
